{# ── Parse Offer Terms ── #}
{%- set annual_ctc      = 0 -%}
{%- set basic           = 0 -%}
{%- set hra             = 0 -%}
{%- set conveyance      = 0 -%}
{%- set other_allowance = 0 -%}
{%- set emp_pf          = 0 -%}
{%- set employer_pf     = 0 -%}
{%- set prof_tax        = 0 -%}
{%- set gratuity        = 0 -%}
{%- set insurance       = 0 -%}

{%- for term in doc.offer_terms -%}
  {%- if "Annual CTC"          in term.offer_term -%}{%- set annual_ctc      = term.value | float -%}{%- endif -%}
  {%- if "Basic"               in term.offer_term -%}{%- set basic           = term.value | float -%}{%- endif -%}
  {%- if "HRA"                 in term.offer_term -%}{%- set hra             = term.value | float -%}{%- endif -%}
  {%- if "Conveyance"          in term.offer_term -%}{%- set conveyance      = term.value | float -%}{%- endif -%}
  {%- if "Other Allowance"     in term.offer_term -%}{%- set other_allowance = term.value | float -%}{%- endif -%}
  {%- if "Employee PF"         in term.offer_term -%}{%- set emp_pf          = term.value | float -%}{%- endif -%}
  {%- if "Employer PF"         in term.offer_term -%}{%- set employer_pf     = term.value | float -%}{%- endif -%}
  {%- if "Professional Tax"    in term.offer_term -%}{%- set prof_tax        = term.value | float -%}{%- endif -%}
  {%- if "Gratuity"            in term.offer_term -%}{%- set gratuity        = term.value | float -%}{%- endif -%}
  {%- if "Insurance"           in term.offer_term -%}{%- set insurance       = term.value | float -%}{%- endif -%}
{%- endfor -%}

{# ── Auto-calculate if only Annual CTC is given ── #}
{%- if annual_ctc and not basic -%}
  {%- set monthly_ctc     = (annual_ctc / 12) | round(0) -%}
  {%- set basic           = (monthly_ctc * 0.50) | round(0) -%}
  {%- set hra             = (basic * 0.50) | round(0) -%}
  {%- set conveyance      = 1600 -%}
  {%- set other_allowance = monthly_ctc - basic - hra - conveyance -%}
{%- else -%}
  {%- set monthly_ctc = basic + hra + conveyance + other_allowance -%}
{%- endif -%}

{%- if not emp_pf     -%}{%- set emp_pf     = 1800 -%}{%- endif -%}
{%- if not employer_pf-%}{%- set employer_pf= 1800 -%}{%- endif -%}
{%- if not prof_tax   -%}{%- set prof_tax   = 208  -%}{%- endif -%}
{%- if not insurance  -%}{%- set insurance  = 5000 -%}{%- endif -%}
{%- if not gratuity   -%}{%- set gratuity   = ((basic * 15) / 26) | round(0) -%}{%- endif -%}

{%- set gross            = basic + hra + conveyance + other_allowance -%}
{%- set total_deductions = emp_pf + prof_tax -%}
{%- set net_pay          = gross - total_deductions -%}

